// Check if the UnityTcp.CustomTool assembly is loaded
var customToolAsm = AppDomain.CurrentDomain.GetAssemblies()
    .FirstOrDefault(a => a.GetName().Name == "UnityTcp.CustomTool");

if (customToolAsm == null)
{
    UnityEngine.Debug.Log("[Diagnostic] UnityTcp.CustomTool assembly NOT loaded");
}
else
{
    UnityEngine.Debug.Log($"[Diagnostic] UnityTcp.CustomTool assembly IS loaded: {customToolAsm.Location}");

    // Check if GenerateTripoModelTool type exists
    var tripoType = customToolAsm.GetType("UnityTcp.Editor.Tools.GenerateTripoModelTool");
    if (tripoType == null)
    {
        UnityEngine.Debug.Log("[Diagnostic] GenerateTripoModelTool type NOT found");
    }
    else
    {
        UnityEngine.Debug.Log($"[Diagnostic] GenerateTripoModelTool type found: {tripoType.FullName}");

        // List all methods with CustomTool attribute
        var methods = tripoType.GetMethods(BindingFlags.Public | BindingFlags.Static);
        foreach (var m in methods)
        {
            var attrs = m.GetCustomAttributes(false);
            foreach (var attr in attrs)
            {
                var attrType = attr.GetType();
                if (attrType.Name.Contains("CustomTool"))
                {
                    var nameProp = attrType.GetProperty("Name");
                    var name = nameProp?.GetValue(attr)?.ToString();
                    UnityEngine.Debug.Log($"[Diagnostic] Found tool method: {m.Name} -> tool_name='{name}'");
                }
            }
        }
    }
}

// Also check what ExecuteCustomTool has registered
var execType = AppDomain.CurrentDomain.GetAssemblies()
    .SelectMany(a => { try { return a.GetTypes(); } catch { return new Type[0]; } })
    .FirstOrDefault(t => t.FullName == "UnityTcp.Editor.Tools.ExecuteCustomTool");

if (execType != null)
{
    var getToolsMethod = execType.GetMethod("GetRegisteredTools", BindingFlags.Public | BindingFlags.Static);
    if (getToolsMethod != null)
    {
        var tools = getToolsMethod.Invoke(null, null) as System.Collections.Generic.IEnumerable<string>;
        if (tools != null)
        {
            var toolList = string.Join(", ", tools);
            UnityEngine.Debug.Log($"[Diagnostic] Registered tools: {toolList}");
        }
    }

    // Try to force re-initialization by resetting the _initialized field
    var initField = execType.GetField("_initialized", BindingFlags.NonPublic | BindingFlags.Static);
    var lockField = execType.GetField("_initLock", BindingFlags.NonPublic | BindingFlags.Static);
    UnityEngine.Debug.Log($"[Diagnostic] _initialized field exists: {initField != null}, value: {initField?.GetValue(null)}");
}
else
{
    UnityEngine.Debug.Log("[Diagnostic] ExecuteCustomTool type NOT found");
}

