using System;
using System.Linq;

var assemblies = AppDomain.CurrentDomain.GetAssemblies().Select(a => a.GetName().Name).ToList();

// Check key assemblies
string[] checkNames = { "UnityTcp.CustomTool", "tjgenerators.Editor", "TJGenerators.Runtime", "UnityTcp.Editor", "Unity.EditorCoroutines.Editor" };
foreach (var name in checkNames)
{
    bool loaded = assemblies.Contains(name);
    UnityEngine.Debug.Log($"[Diagnostic] Assembly '{name}': {(loaded ? "LOADED" : "NOT LOADED")}");
}

// Check if System.IO.Compression DLL exists
string dataPath = UnityEngine.Application.dataPath;
string projectRoot = dataPath.Replace("/Assets", "");
string[] dllChecks = {
    "System.IO.Compression.dll",
    "System.IO.Compression.FileSystem.dll"
};

// Check NuGet/packages folders
foreach (var dll in dllChecks)
{
    // Check if it's in the assembly list
    bool inAsm = assemblies.Any(a => a.Contains("System.IO.Compression"));
    UnityEngine.Debug.Log($"[Diagnostic] System.IO.Compression in loaded assemblies: {inAsm}");
}

// List all TJGenerators-related assemblies
var tjAssemblies = assemblies.Where(a => a.ToLower().Contains("tjgen") || a.ToLower().Contains("tuanjie") || a.ToLower().Contains("customtool"));
UnityEngine.Debug.Log($"[Diagnostic] TJ/custom assemblies: {string.Join(", ", tjAssemblies)}");

// Check Editor.log for compilation errors
// Actually, let's try to force load the assembly
try 
{
    var asm = System.Reflection.Assembly.Load("UnityTcp.CustomTool");
    UnityEngine.Debug.Log($"[Diagnostic] Force-loaded UnityTcp.CustomTool: {asm != null}");
}
catch (Exception ex)
{
    UnityEngine.Debug.LogWarning($"[Diagnostic] Cannot load UnityTcp.CustomTool: {ex.Message}");
}

