using System;
using System.Linq;
using System.IO;

// Check if System.IO.Compression exists as a precompiled DLL anywhere
string dataPath = UnityEngine.Application.dataPath;
string projectRoot = dataPath.Replace("/Assets", "");

// Check common locations for System.IO.Compression.dll
string[] searchPaths = {
    Path.Combine(dataPath, "../.codely.packages"),
    Path.Combine(dataPath, "../.codely-cli/extensions/TJGenerators/Packages/cn.tuanjie.ai.generators"),
    Path.Combine(dataPath, "Plugins"),
};

foreach (var searchPath in searchPaths)
{
    if (Directory.Exists(searchPath))
    {
        var dlls = Directory.GetFiles(searchPath, "System.IO.Compression*.dll", SearchOption.AllDirectories);
        foreach (var dll in dlls)
        {
            UnityEngine.Debug.Log($"[Diagnostic] Found DLL: {dll}");
        }
    }
}

