AssetDatabase.Refresh();
var prefab = AssetDatabase.LoadAssetAtPath<GameObject>("Assets/TJGenerators/History/SeparatoryFunnel.prefab");
if (prefab == null) {
    AssetDatabase.ImportAsset("Assets/TJGenerators/History/SeparatoryFunnel.prefab", ImportAssetOptions.ForceUpdate);
    prefab = AssetDatabase.LoadAssetAtPath<GameObject>("Assets/TJGenerators/History/SeparatoryFunnel.prefab");
}
if (prefab == null) { Debug.LogError("Prefab 未找到: Assets/TJGenerators/History/SeparatoryFunnel.prefab"); return; }

var instance = PrefabUtility.InstantiatePrefab(prefab) as GameObject;
instance.name = "SeparatoryFunnel";

// Find the Table to confirm position
var table = GameObject.Find("Table");
Vector3 pos = new Vector3(2.33f, 0.07f, -16.28f);
if (table != null)
{
    Debug.Log($"[PlaceAsset] Found Table at: {table.transform.position}");
    pos = table.transform.position;
}

instance.transform.position = pos;
instance.transform.rotation = Quaternion.identity;
instance.transform.localScale = Vector3.one;

Debug.Log($"[PlaceAsset] Placed SeparatoryFunnel at: {instance.transform.position}");

Undo.RegisterCreatedObjectUndo(instance, "放置 SeparatoryFunnel Prefab");
UnityEditor.SceneManagement.EditorSceneManager.MarkAllScenesDirty();

